CREATE TABLE booking_series (
	id INTEGER NOT NULL, 
	weekdays VARCHAR(20) NOT NULL, 
	until DATE NOT NULL, 
	created_by VARCHAR(200), 
	created_at DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE room (
	id INTEGER NOT NULL, 
	name VARCHAR(100) NOT NULL, 
	capacity INTEGER, 
	sort_order INTEGER, 
	active BOOLEAN NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (name)
);
CREATE INDEX ix_booking_date ON booking (date);
CREATE INDEX ix_booking_room_date ON booking (room_id, date);
